import { useState, useMemo } from "react";

function classifyType(raw) {
  if (!raw) return "residential";
  const t = raw.toLowerCase();
  const hasRes = t.includes("residential") || t.includes("coastal");
  const hasCom = t.includes("commercial") || t.includes("admin") || t.includes("medical");
  if (hasRes && hasCom) return "mixed";
  if (hasCom) return "commercial";
  return "residential";
}

function typeLabel(raw) {
  const t = classifyType(raw);
  if (t === "commercial") return "تجاري";
  if (t === "mixed") return "مختلط";
  return "سكني";
}

function typeBadgeClass(raw) {
  const t = classifyType(raw);
  if (t === "commercial") return "bg-orange-50 text-orange-600 border-orange-100";
  if (t === "mixed") return "bg-purple-50 text-purple-600 border-purple-100";
  return "bg-blue-50 text-blue-600 border-blue-100";
}

